// // This module implements a 4-bit synchronous down-counter with enable and reset inputs.
module synchronous_up_counter (
  input clk,
  input reset,
  input enable,
  output reg [3:0] count
);

always @(posedge clk) begin
  if (reset) begin
    count <= 4'b0000;
  end else if (enable) begin
    count <= count + 1;
  end
end

endmodule
